def update_guild_status(treeview):
    # Get the current user ID
    user_id = get_current_user_id()
    if not user_id:
        print("User not authenticated.")
        return

    # Check which guild the player is currently in
    membership_response = supabase.table('Members').select('guild_id').eq('user_id', user_id).execute()
    current_guild_id = membership_response.data[0]['guild_id'] if membership_response.data else None

    # Update the Treeview
    for item in treeview.get_children():
        guild_id = item  # Treeview item's ID corresponds to the guild's ID
        if guild_id == current_guild_id:
            # For the current guild
            treeview.item(item, values=(
                treeview.item(item, "values")[0],  # Guild Name
                treeview.item(item, "values")[1],  # Rank
                treeview.item(item, "values")[2],  # Members
                "In Guild"  # Text for the current guild
            ))
        else:
            # For other guilds
            treeview.item(item, values=(
                treeview.item(item, "values")[0],  # Guild Name
                treeview.item(item, "values")[1],  # Rank
                treeview.item(item, "values")[2],  # Members
                "Switch Guild"  # Text for other guilds
            ))


    


hovered_item = None

def on_treeview_hover(event):
    global hovered_item
    # Identify the item and column under the mouse cursor
    item_id = treeview.identify_row(event.y)
    column = treeview.identify_column(event.x)

    # Get the current user ID and the player's current guild
    user_id = get_current_user_id()
    membership_response = supabase.table('Members').select('guild_id').eq('user_id', user_id).execute()
    current_guild_id = membership_response.data[0]['guild_id'] if membership_response.data else None

    # Reset previously hovered item if it's different
    if hovered_item and hovered_item != item_id:
        # Clear the text completely for previously hovered item
        treeview.item(hovered_item, values=(
            treeview.item(hovered_item, "values")[0],  # Name
            treeview.item(hovered_item, "values")[1],  # Rank
            treeview.item(hovered_item, "values")[2],  # Members
            ""  # Clear text for previously hovered item
        ))
        hovered_item = None

    # Only process hover events over the 'Join' column
    if item_id and column == '#4':
        # Update the hovered item
        hovered_item = item_id

        # Determine the hover text
        hover_text = "In Guild" if item_id == current_guild_id else "Switch Guild"

        # Change the text dynamically when hovered
        treeview.item(item_id, values=(
            treeview.item(item_id, "values")[0],  # Name
            treeview.item(item_id, "values")[1],  # Rank
            treeview.item(item_id, "values")[2],  # Members
            hover_text  # Dynamic hover text
        ))

def on_treeview_leave(event):
    global hovered_item
    # Reset the last hovered item's text to be empty when mouse leaves
    if hovered_item:
        treeview.item(hovered_item, values=(
            treeview.item(hovered_item, "values")[0],  # Name
            treeview.item(hovered_item, "values")[1],  # Rank
            treeview.item(hovered_item, "values")[2],  # Members
            ""  # Clear the text when mouse leaves
        ))
        hovered_item = None




def on_treeview_click(event):
    # Identify the item clicked
    item_id = treeview.identify_row(event.y)
    column = treeview.identify_column(event.x)

    if not item_id:
        print("No guild selected.")
        return

    # Fetch current user's guild
    user_id = get_current_user_id()
    membership_response = supabase.table('Members').select('guild_id').eq('user_id', user_id).execute()
    current_guild_id = membership_response.data[0]['guild_id'] if membership_response.data else None

    if column == '#4':  # Check if it's the 'Join/Switch' column
        if item_id == current_guild_id:
            print("Already in this guild. Action not allowed.")
        else:
            print(f"Switching to guild with ID: {item_id}")
            # Switch guild logic here
            switch_guild(user_id, item_id)
            update_guild_status(treeview)

def switch_guild(user_id, new_guild_id):
    # Remove the user from the current guild
    supabase.table('Members').delete().eq('user_id', user_id).execute()
    
    # Add the user to the new guild
    supabase.table('Members').insert({'user_id': user_id, 'guild_id': new_guild_id}).execute()
    print(f"Switched to guild with ID: {new_guild_id}")


def get_current_user_id():
    try:
        user_response = supabase.auth.get_user(session["access_token"])  # Synchronous call
        if user_response and user_response.user:
            return user_response.user.id
        else:
            print("User is not authenticated.")  # Add logging for better debugging
            return None
    except Exception as e:
        print(f"Error getting user: {e}")
        return None
    
# Fetch guilds and populate listbox
def load_guilds(treeview):
    # Fetch guilds from Supabase
    response = supabase.table('Guilds').select('id', 'name', 'rank', 'member_count').execute()

    guilds = response.data if response.data else []

    # Sort guilds based on the custom rank priority
    sorted_guilds = sorted(guilds, key=lambda guild: rank_priority.get(guild['rank'], float('inf')))

    # Clear existing Treeview entries
    for item in treeview.get_children():
        treeview.delete(item)

    # Insert sorted guilds into the Treeview
    for guild in sorted_guilds:
        print(f"Inserting guild with ID: {guild['id']}")  # Debugging
        treeview.insert('', 'end', iid=guild['id'], values=(
            guild['name'], guild['rank'], guild['member_count'], ""))  # Empty Join initially



        
