def join_guild(guild_id):
    # Fetch guild details
    response = supabase.table('Guilds').select('*').eq('id', guild_id).execute()
    guild = response.data[0] if response.data else None

    if guild:
        # Assuming 'user_id' is stored in the 'status' table under the 'name' column
        user_response = supabase.table('status').select('name').eq('user_id', get_current_user_id()).execute()
        
        # Extract the user ID from the response data
        user_id = user_response.data[0]['name'] if user_response.data else None  # Make sure to handle missing data

        if not user_id:
            print("User not found.")
            return

        # Check if the user is already a member
        membership_check = supabase.table('Members').select('*').eq('user_id', user_id).eq('guild_id', guild_id).execute()
        if membership_check.data:
            return

        # Add user to the guild
        insert_response = supabase.table('Members').insert({'user_id': user_id, 'guild_id': guild_id}).execute()
    else:
        print("Guild not found.")


